def pow_poly(a_,b_,c_):     # 快速幂算法实现
    r = 1
    while b_:
        if b_ % 2 == 1:
            r *= a_
            r %= c_
        a_ = a_ ^ 2
        a_ %= c_
        b_ >>= 1
    return r

